import{_ as o,o as t,c as a,a7 as r}from"./chunks/framework.BgApuQ2e.js";const s="/images/7-ways-to-be-insufferable-on-facebook/Newsfeed.jpg",n="/images/7-ways-to-be-insufferable-on-facebook/Facebook-Status-Guide-How-to-Be-Unannoying.jpg",l="/images/7-ways-to-be-insufferable-on-facebook/brag-2528life-2529.jpg",i="/images/7-ways-to-be-insufferable-on-facebook/brag-2528undercover-2529.jpg",p="/images/7-ways-to-be-insufferable-on-facebook/brag-2528relationship-2529.jpg",g="/images/7-ways-to-be-insufferable-on-facebook/cliffhanger.jpg",b="/images/7-ways-to-be-insufferable-on-facebook/literal.jpg",m="/images/7-ways-to-be-insufferable-on-facebook/Literal-Graph.jpg",c="/images/7-ways-to-be-insufferable-on-facebook/inexplicably-public.jpg",f="/images/7-ways-to-be-insufferable-on-facebook/oscar-speech.jpg",h="/images/7-ways-to-be-insufferable-on-facebook/obvious-combined.jpg",u="/images/7-ways-to-be-insufferable-on-facebook/enlightenment.jpg",k="/images/7-ways-to-be-insufferable-on-facebook/pinit_fg_en_rect_gray_20.png",I=JSON.parse('{"title":"7 Ways to Be Insufferable on Facebook","description":"","frontmatter":{"title":"7 Ways to Be Insufferable on Facebook","titleZh":"Facebook 上惹人厌的七种行为","date":"2013-07-08T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html","slug":"7-ways-to-be-insufferable-on-facebook"},"headers":[],"relativePath":"posts/7-ways-to-be-insufferable-on-facebook.md","filePath":"posts/7-ways-to-be-insufferable-on-facebook.md","lastUpdated":1782886257000}'),d={name:"posts/7-ways-to-be-insufferable-on-facebook.md"};function A(_,e,w,y,q,F){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="facebook-上惹人厌的七种行为-·-7-ways-to-be-insufferable-on-facebook" tabindex="-1">Facebook 上惹人厌的七种行为 · 7 Ways to Be Insufferable on Facebook <a class="header-anchor" href="#facebook-上惹人厌的七种行为-·-7-ways-to-be-insufferable-on-facebook" aria-label="Permalink to &quot;Facebook 上惹人厌的七种行为 · 7 Ways to Be Insufferable on Facebook&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html</a> · 2013-07-08</p></blockquote><p><a href="https://2.bp.blogspot.com/-wfCwz-unaoc/UdfHmfudD7I/AAAAAAAAEJ4/1gD5Mhgf4ww/s1600/Newsfeed.jpg" target="_blank" rel="noreferrer"><img src="'+s+'" alt="facebook news feed"></a></p><p>那段记忆无比清晰。</p><p>2013 年元旦。我正惬意地度过下午,打开邮箱,发现一个朋友转给我一条她所谓的、来自她 News Feed 的「特别令人发指」的 Facebook 状态,作者我们就叫他 Daniel 吧。内容是这样的:</p><blockquote><p><em>2012 对我来说是个大大大大的年份。我辞掉了 NBC 那份超棒的工作,搬回芝加哥。我开始和我的天使 Jaime Holland 约会。我开始练瑜伽(感谢 Jake Fisher 和 Jonah Perlstein!)。我和 Matthew Johannson 一起写了一张专辑。又写了一张我很自豪的专辑。我跟 Owen Wilson 一起玩,和 Will Ferrell 合作了一个了不起的项目。我跟 David Gregory 聊了聊 Barack Obama。跳了舞。加入了一个躲避球队。得了几个奖。帮我妹妹策划了她的暑期旅行。游了很多次泳。打了一点高尔夫。哭得比你想象的还要多。读了《盖普眼中的世界》。看了《现代启示录》。去迈阿密看了 NBA 总决赛。和 Davey Welch 一起喝了我这辈子喝过最好喝的橙汁。发推特了。参加了在纽约上州办的几场超棒的婚礼。喝了多得离谱的牛奶。学会了怎么做沙画。看了一场很棒的灯光秀。看了天使队和湖人队。爱上了 Jawbone Up。和 Jaime 一起做饭。和 Jaime 一起打理花园。和 Jaime 一起看《国土安全》。和 Jaime 摔跤玩。和 Jaime 一起笑了好几个小时。爱上了 Jaime 的家人。参与了一部话剧。玩了《魔兽世界》。玩了点即兴喜剧。弹了超多吉他。真的是狂野又美妙的一年。多么美妙的世界。</em></p></blockquote><p>读完之后,我意识到我没拿手机的那只手正死死抓着自己的额头,把额头上的皮都用力揪到了一起。那种表情,就跟有人逼我看一场活人被慢慢剥皮的现场直播时会有的表情一样。</p><p>它把所有事情里所有糟糕的一面,一次性地全部集齐了。</p><p>但我没有远离这份恐怖,反而沉浸其中。我一遍一遍地读,着迷于一段文字怎么能这么咄咄逼人地令人反感。</p><p>这让我开始思考:糟糕的 Facebook 行为到底糟糕在哪儿,为什么另一些 Facebook 行为完全不烦人。归根结底就是一条非常简单的规则:</p><h4 id="一条-facebook-状态如果主要是在服务作者本人、对读者毫无正面价值-那它就烦人。" tabindex="-1"><strong>一条 Facebook 状态如果主要是在服务作者本人、对读者毫无正面价值,那它就烦人。</strong> <a class="header-anchor" href="#一条-facebook-状态如果主要是在服务作者本人、对读者毫无正面价值-那它就烦人。" aria-label="Permalink to &quot;**一条 Facebook 状态如果主要是在服务作者本人、对读者毫无正面价值,那它就烦人。**&quot;">​</a></h4><p><a href="https://1.bp.blogspot.com/-R7TUvKTuTwM/UdfIBP25ynI/AAAAAAAAELU/WAM-tlczsk4/s1600/Facebook+Status+Guide+-+How+to+Be+Unannoying.jpg" target="_blank" rel="noreferrer"><img src="'+n+'" alt="venn diagram: only posts that do something positive for the reader are unannoying"></a></p><p>为了稍微展开一下这一点,我们先从「<em>不</em>烦人」的状态有哪些共同特征说起。</p><p><strong>一条不烦人的 Facebook 状态,通常必须具备下面两点之一:</strong></p><p><strong>1) 有趣 / 有信息量</strong></p><p><strong>2) 搞笑/有趣/娱乐性的</strong></p><p>知道为什么这些不烦人吗?因为这两类东西为<em>我,也就是读者</em>做了点什么。它们让我的一天<em>好过</em>了那么一点点。</p><p>理想情况下,有趣的状态应该是既引人入胜又有原创性的(或者链接到这样的内容),搞笑的状态应该让人笑到不行。但<em>稍微有点意思</em>我也照单全收——至少我们面对的还是好人。</p><p>另一方面,<strong>烦人的状态通常散发着以下五种动机中一种或多种的气息:</strong></p><p><strong>1) 塑造形象。</strong> 作者想影响别人对她的看法。</p><p><strong>2) 自恋。</strong> 作者觉得自己的想法、观点和人生哲学<em>很重要</em>。作者本人和作者的生活本身就很有意思。 <strong>3) 渴求关注。</strong> 作者想要关注。</p><p><strong>4) 引发嫉妒。</strong> 作者想让别人嫉妒他或他的生活。</p><p><strong>5) 孤独。</strong> 作者感到孤独,想让 Facebook 让自己好受点。这是五种里最不可恶的——但看到一个孤独的人在 Facebook 上表现得孤独,会让我和其他所有人都觉得难过。所以这个人本质上是在<em>传播</em>自己的悲伤,这是件糟糕的事情,所以也上榜了。</p><p>Facebook 被这五种动机搞得乌烟瘴气——除了少数几个真正圣人级别的人之外,我认识的大多数人,当然也包括我自己,都或多或少在这里那里干过这种蠢事。这是场瘟疫。</p><p>以下列出最常见的几种冒犯类型:</p><h2 id="在-facebook-上让人受不了的-7-种方式" tabindex="-1"><strong>在 Facebook 上让人受不了的 7 种方式</strong> <a class="header-anchor" href="#在-facebook-上让人受不了的-7-种方式" aria-label="Permalink to &quot;**在 Facebook 上让人受不了的 7 种方式**&quot;">​</a></h2><h2 id="_1-炫耀" tabindex="-1"><strong>1) 炫耀</strong> <a class="header-anchor" href="#_1-炫耀" aria-label="Permalink to &quot;**1) 炫耀**&quot;">​</a></h2><p>炫耀是不幸的 Facebook 行为中一个如此核心的存在,以至于需要拆成三个子类:</p><h3 id="_1a-我的生活相当精彩-型炫耀" tabindex="-1"><strong>1a) “我的生活相当精彩” 型炫耀</strong> <a class="header-anchor" href="#_1a-我的生活相当精彩-型炫耀" aria-label="Permalink to &quot;**1a) “我的生活相当精彩” 型炫耀**&quot;">​</a></h3><p><a href="https://3.bp.blogspot.com/-wssvBibXdt4/UdfH676GmDI/AAAAAAAAEK4/8OZ8aeKM4d8/s1600/brag+%2528life%2529.jpg" target="_blank" rel="noreferrer"><img src="'+l+'" alt="stick figure looking pleased with himself"></a></p><p><strong>描述:</strong> 一条让你的生活听起来很棒的帖子,不管是宏观层面上(拿到了梦想的工作、拿到了学位、爱上新公寓),还是微观层面上(即将踏上一段美妙的旅程、周末有大活动、要和朋友出去疯玩一晚、刚过了美妙的一天)。</p><p><strong>例子:</strong></p><ul><li><em>猜猜谁刚收到了 TFA 的录取通知书!!!</em></li><li><em>夏威夷!</em></li><li><em>停车场烧烤、巨人队比赛、和 Dave、Matt、Paul、Andy 一起出去玩。爱死你了,星期六。</em></li></ul><p><strong>发帖的核心原因:</strong> 塑造形象(我很成功;我很幸福;我社交生活丰富),引发嫉妒</p><p>所以往好了说,你只是对自己的生活激动得不行,非要告诉每个人不可;往坏了说,你就是特意想让别人对自己的生活感觉更糟、嫉妒你的生活。介于两者之间的是,你精心算计地字斟句酌,作为一场令人反感又毫无遮掩的活动的一部分——目的是让别人以某种特定的方式看待你。</p><p>我们不妨往好处想,假设你只是太兴奋了,需要向什么人炫耀一下。就算是这样,人生中唯一可以炫耀的对象也只有你的密友、伴侣和家人——而这就是邮件、短信、电话和当面聊天存在的意义。你那点自我满足的小时刻,对不太熟的人来说是极其烦人的,而这些人恰恰构成了会被这条状态轰炸的绝大多数人。</p><h3 id="_1b-卧底型炫耀" tabindex="-1"><strong>1b) 卧底型炫耀</strong> <a class="header-anchor" href="#_1b-卧底型炫耀" aria-label="Permalink to &quot;**1b) 卧底型炫耀**&quot;">​</a></h3><p><a href="https://4.bp.blogspot.com/-gfDg6Spaz38/UdfH7GuRioI/AAAAAAAAEKM/hmrZlk6uQ4Q/s1600/brag+%2528undercover%2529.jpg" target="_blank" rel="noreferrer"><img src="'+i+'" alt="stick figure wearing mask"></a></p><p><strong>描述:</strong> 和上面的赤裸炫耀差不多,只不过披上了一层拙劣的伪装。这类包括所有的<a href="https://www.grantland.com/story/_/id/6665462/humblebrag-hall-fame" target="_blank" rel="noreferrer">凡尔赛体 (humblebrags)</a>、间接炫耀、伪装成吐槽的炫耀,等等。</p><p><strong>例子:</strong></p><ul><li><em>看来现在博士学位都发给骗子和酒鬼了。活着的年代真是精彩!</em></li><li><em>我整个夏天都会在外面旅行,如果有人认识想在 7 月和 8 月转租苏豪区公寓的人,请告诉我。</em></li><li><em>下班走回家的路上,被人吹了两次口哨,按了两次喇叭,还有一辆车差点因为减速盯着我看而引发事故。有时候我真的很讨厌男人。</em></li></ul><p><strong>发帖的核心动机:</strong> 塑造形象、引发嫉妒</p><p>一方面,这些人至少还有点自知之明,会给自己的炫耀套上<em>点什么</em>。另一方面,他们的核心动机跟赤裸炫耀者一模一样,而且看完这些例子,相比之下第一类人简直显得可爱了。</p><h3 id="_1c-我恋爱恋得超棒-型炫耀" tabindex="-1"><strong>1c) “我恋爱恋得超棒”型炫耀</strong> <a class="header-anchor" href="#_1c-我恋爱恋得超棒-型炫耀" aria-label="Permalink to &quot;**1c) “我恋爱恋得超棒”型炫耀**&quot;">​</a></h3><p><a href="https://3.bp.blogspot.com/-psKyT6m_9JA/UdfH7BidnoI/AAAAAAAAEKI/MqT6LiVXl5U/s1600/brag+%2528relationship%2529.jpg" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Stick figure with hearts floating around head"></a></p><p><strong>描述:</strong> 公开表达你对伴侣极度正面的感情,或者晒一段能证明你俩感情完美无缺的小故事。</p><p><strong>例子:</strong></p><ul><li><em>给了我一个惊喜,带我去佛蒙特的小木屋住两晚。我只能说,Wow,这男朋友绝了。</em></li><li><em>谢谢你,Rachel,给了我这辈子最棒的一年。</em></li><li><em>期待和老婆一起过一个下雨的星期天,披萨、游戏和电影。</em></li></ul><p><strong>发帖的核心动机:</strong> 塑造形象(顺便说一下,我有男朋友;我在谈一段美妙的恋爱)、引发嫉妒</p><p>这里塑造形象和引发嫉妒的动机简直是透明的。唯一稍微不那么让人反胃的可能性是:这是一种巩固关系本身的尝试,通过一种比私下说说更有分量的方式来表达感情。可是——真的吗?就因为你想不出更有创意的方式来夸张地表达自己,就要把我们 800 个人拖进这坨屎里?</p><p>当发帖的是个男生时,有一种非常搞笑的可能性:要么是他犯了什么错正在补救,要么是他女朋友的朋友的男朋友以前干过类似的破事,导致他女朋友从那时起就对他有 10% 的不爽,所以他现在终于不得不硬着头皮发一条。</p><p>事实是,这种事没什么好辩解的,因为如果你真的觉得非要把你的恋情糊到 Facebook 上,有的是社会可接受的方式——尽情换情侣头像吧,并且享受把状态改成「恋爱中」「已订婚」和「已婚」时那三次分别收获的点赞和评论的掌声。</p><h2 id="" tabindex="-1">** <a class="header-anchor" href="#" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="2"><li>悬念党 (The Cryptic Cliffhanger)**</li></ol><p><a href="https://1.bp.blogspot.com/-fBsd-6S8axk/UdfH7rWxaJI/AAAAAAAAEKY/tFgqftpVexY/s1600/cliffhanger.jpg" target="_blank" rel="noreferrer"><img src="'+g+'" alt="&quot;What has ten fingers and ten toes and loves attention&quot; drawing of ransom-note-style paper with cut out letters"></a></p><p><strong>描述:</strong> 一条明确暗示你生活中正在发生某件好事或坏事、但完全不透露任何细节的帖子。 <strong>例子:</strong></p><ul><li><em>够了。我 再也 不约会了。</em></li><li><em>今天可能会是个大大大日子……</em></li><li><em>正是这样的时刻,让所有的挣扎和痛苦都值得了。</em></li><li><em>唉啊啊啊啊啊啊</em></li></ul><p><strong>发帖的核心原因:</strong> 渴求关注</p><p>这类帖子好玩的地方在于看那些不可避免的评论,然后看作者如何回应这些评论——如果他回应的话。这个过程会把作者分进以下四个子类别之一:</p><ul><li><p><strong>明星型:</strong> 作者保持沉默,把评论者当成围观的粉丝。</p></li><li><p><strong>800 人共同的作精女友型:</strong> 作者在评论里把一切都解释清楚,意思是他本来就想公开谈论此事,但他不想直接 <em>告诉</em> 大家,他要大家 <em>来问</em> 他。</p></li><li><p><strong>受苦受难主角型:</strong> 是件坏事。作者回复了,但保持神秘——她很难过,而且「不太想聊这个」。</p></li><li><p><strong>万人迷小公主型:</strong> 是件让人兴奋的事。作者回复了,但保持神秘——事情真的很棒,他「现在还不能说,但你们很快就会知道啦!」现在你在屏息等待这个大新闻时,走路都得多蹦跶两下!这一种特别值得一提,因为它同时融合了自恋、诱发嫉妒和形象打造。生活中有这样的人真是太有意思了!</p></li></ul><h2 id="-1" tabindex="-1">** <a class="header-anchor" href="#-1" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="3"><li>字面状态更新 (The Literal Status Update)**</li></ol><p><a href="https://4.bp.blogspot.com/-dHEsXWfjhhM/UdfH8TtFOGI/AAAAAAAAEK8/FJqwq2o6Qws/s1600/literal.jpg" target="_blank" rel="noreferrer"><img src="'+b+'" alt="stick figure holding banana: I must remember to tell everyone about this banana.."></a></p><p><strong>描述:</strong> 对某人平淡无奇一天的一条真·状态更新。</p><p><strong>例子:</strong></p><ul><li><em>去健身房,然后回来读课本</em></li><li><em>饺子!</em></li><li><em>论文终于写完了!</em></li></ul><p><strong>发帖的核心原因:</strong> 孤独;自恋;以为状态更新就真的是要更新一下状态</p><p>请允许我展示一张图——</p><p><a href="https://1.bp.blogspot.com/-bRQ1LvSo-ts/UdxarjvH7fI/AAAAAAAAEMU/wfCA47_3EXI/s1600/Literal+Graph.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Nested circles drawing. Big circle: Parts of your life that interest you (e.g. Tonight&#39;s a gym night). Smaller circle: Parts of your life that interest your Mom (E.g. Work was good this week). Very small circle: Parts of your life that interest your good friends (e.g. I got a promotion!) Tiny circle: Parts of your life that interest most of your Facebook friends (e.g. I&#39;m engaged!)"></a></p><p><em>“终于把论文写完了!”</em> 好吧……<em>所以呢?</em> 你想要什么?一堆对你的挣扎毫无情感投入的人送上假惺惺的祝贺?写完论文属于上图中的绿色地带,或者如果你为它埋头苦干了几个月,可能能勉强蹭到橙色的<em>外</em>边缘。对于 90% 以上会看到这条状态的人来说,它<em>根本</em>够不着红色地带——而红色地带才是他们唯一在乎的。</p><p><em>去健身房了,然后读课本</em>。哦,今晚就这个安排啊?你这话到底是<em>说给谁听</em>的?我真的很想搞清楚。从下班到抵达健身房之间的某个时刻,你产生了一个冲动,拿出手机敲下了这条状态。然后又把手机收了起来。告诉我这一切完成了什么。</p><p>我们说的这可是深蓝色地带啊,意思是就连你妈都不在乎。很多烦人的状态离红色地带都很远,但它们至少都在某种程度上服务于作者本人,所以才会被发出来。</p><p>但关于你日程的信息既不能塑造你的形象,也不能让任何人嫉妒——所以它看起来更像是&quot;渴望关注&quot;那个可怜的表亲,叫&quot;孤独&quot;。我觉得 Facebook 能给孤独的人一个倾诉一天经历的对象,这挺好的,而且如果这些状态不附带一个副产品——提醒其他所有人生命毫无意义、他们终将死去——那它们也用不着上这个榜单。</p><p>另一个可能的解释是<em>严重</em>自恋,好像因为你是你,所以你生活中哪怕最微小的细节别人都会觉得有趣。大明星生活里的一个诡异之处就是,人们痴迷于他们的一切,连蓝色地带都不放过。如果你不是大明星,那你没有这种烦恼,我保证。</p><h2 id="_4-莫名公开的私人消息" tabindex="-1"><strong>4) 莫名公开的私人消息</strong> <a class="header-anchor" href="#_4-莫名公开的私人消息" aria-label="Permalink to &quot;**4) 莫名公开的私人消息**&quot;">​</a></h2><p><a href="https://4.bp.blogspot.com/-YuX8yNn3mY4/UdfH8P9Y7YI/AAAAAAAAEKk/yk_9Hk9k624/s1600/inexplicably+public.jpg" target="_blank" rel="noreferrer"><img src="'+c+'" alt="stick figure holding tin-can-and-string telephone but also a megaphone"></a></p><p><strong>描述:</strong> 一个人对另一个人的公开发帖,毫无理由需要公开。</p><p><strong>例子:</strong></p><ul><li><em>好想你!我们什么时候一起玩?</em></li><li><em>和 Julie Epstein 还有 Emily Rothchild 度过了美好的周末。我爱我的姐妹们!</em></li><li>全都是圈内梗。</li></ul><p><strong>发帖的核心原因:</strong> 打造形象;引发嫉妒;自恋;或者你已经 80 岁了,搞不清公开帖子和私信有什么区别。</p><p>除了我奶奶那种情况之外,没有任何好理由这么干。<em>好</em>是关键词。倒是有<em>一堆</em>非常令人烦躁的理由让人这么干。我们来列一下:</p><ul><li><p>让自己显得又酷又社交达人,把自己的社交生活包装得多彩又有趣</p></li><li><p>向所有人展示你和收件人是多好的朋友</p></li><li><p>让别人嫉妒或者对自己的生活感到糟糕</p></li><li><p>因为你表现得像还在上高中一样,像那些自以为社交状况对别人来说很重要的风云人物</p></li></ul><p>我唯一喜欢的一种可能性是:这条消息<em>专门</em>是写给某一个大概率会看到的人看,以引起他/她的嫉妒——不管是前任还是他们讨厌的朋友。那种恶意极端到越过远方那条底线,反而变得棒极了。</p><h3 id="-2" tabindex="-1">** <a class="header-anchor" href="#-2" aria-label="Permalink to &quot;**&quot;">​</a></h3><ol start="5"><li>突如其来的奥斯卡获奖感言**</li></ol><p><a href="https://2.bp.blogspot.com/-zHpjC6UR2-k/UdfH9DzMh9I/AAAAAAAAELI/bUh9boY5Zps/s1600/oscar+speech.jpg" target="_blank" rel="noreferrer"><img src="'+f+'" alt="stick figure crying at podium holding award"></a></p><p>** 描述:** 毫无缘由、也不针对任何具体对象的一场爱意大爆发。</p><p><strong>例子:</strong> <em>我只想说,我对所有触动过我生命的你们心怀感激。你们的支持对我意义非凡,没有你们,我根本熬不过过去一年里的那么多事情!</em></p><p><strong>发帖的核心原因:</strong> 渴求关注</p><p>我拒绝相信你对你 Facebook 上的 800 个好友真的涌起了发自内心的爱意。就算你突然对最好的朋友和家人情绪汹涌,一条公开状态真的是你会选择的表达方式吗?给几个人发封邮件或短信不是更私人、更真诚吗?不重要,因为这里发生的根本不是那么回事。</p><p>这里发生的事情其实可以归结为一句话:「大家好!我在这儿!快抱抱我!」你心里清楚,不管你是谁,这类状态收到的必然回应就是几十个点赞式的拥抱和评论式的臂膀轻拍。这不就有点太黏人了吗?你写这条帖子的时候感受到的并不是爱——你感受到的是<em>需要被爱</em>。</p><p>唯一稍微可以接受的场合是当它成为某种大规模集体拥抱的一部分,比如感恩节或圣诞节。如果你在感恩节打开 Facebook,你会被数百条突如其来的奥斯卡获奖感言洗礼。(顺便说一句,这些我也宁可不看。)</p><h2 id="-3" tabindex="-1">** <a class="header-anchor" href="#-3" aria-label="Permalink to &quot;**&quot;">​</a></h2><ol start="6"><li>蠢到不能再蠢的观点**</li></ol><p><a href="https://3.bp.blogspot.com/-IxS66M_7k7M/UdplwHJ_9GI/AAAAAAAAELo/1rgt95zUq7Q/s1600/obvious+combined.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt="stick figure looking through telescope on sunny day. Second panel: &quot;The sun is bright.&quot;"></a></p><p>**描述:**每当发生一件大事,总有人发帖插一嘴,重复我们已经听过 1000 遍的观点。</p><p><strong>例子:</strong></p><ul><li><em>我对正在为自由而战的埃及人民深表同情。每个人都有权享有自由,我祈祷他们能够胜利。</em></li><li><em>在这场难以言喻的悲剧发生后,我的心和祷告与纽敦 (Newtown) 的家庭们同在。我无法用言语表达对那些失去孩子的家庭的哀伤。</em></li><li><em>我对奥巴马 (Obama) 的第一个任期有些失望,但我很高兴他连任成功,并对他的第二个任期充满期待。</em></li></ul><p>**发帖的核心原因:**自恋;人设塑造(我是那种会有这种观点或反应的人;我很聪明,我能说一些成熟的话)</p><p>这些之所以讨厌,是因为 A) 对于一件媒体已经从各个角度铺天盖地报道过的事件,你说的东西一点也不新鲜、一点也不有趣;B) 你把一件重大的、往往还是悲剧性的事件,变得部分是关于你自己的。你对儿童遭屠杀感到的悲伤其实并不是拼图里的关键一块,而且我们真的不需要你来描述这件事在你个人视角下是什么样子——尤其是当这个&quot;视角&quot;其实就是一块透明的玻璃时。如果我想在悲剧旁边配一份自恋当小菜,我直接去看名人推特就行了。</p><h2 id="_7-通往开悟的一步" tabindex="-1"><strong>7) 通往开悟的一步</strong> <a class="header-anchor" href="#_7-通往开悟的一步" aria-label="Permalink to &quot;**7) 通往开悟的一步**&quot;">​</a></h2><p><a href="https://4.bp.blogspot.com/-zQk44zHAw2k/UdfH7pti9TI/AAAAAAAAEKc/at0YxOBzyLE/s1600/enlightenment.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt="cross-legged stick figures facing elderly wise stick figure"></a></p><p>**描述:**没人问、但你偏要送上的一颗智慧金句。</p><p><strong>例子:</strong></p><ul><li><em>&quot;平静来自内心。切勿向外寻求。&quot;~佛陀</em></li><li><em>你要专心仰赖耶和华,不可倚靠自己的聪明;在你一切所行的事上都要认定他,他必指引你的路。~箴言 3:5-6</em></li><li><em>我不明白新年到底有什么好大惊小怪的,大家嚷嚷着明年自己要变得多么不同。如果你真想变得更好,哪一天都无所谓……我?我明天还是今天的我。</em></li></ul><p>**发帖的核心原因:**人设塑造;自恋</p><p>哦,该从哪儿说起呢。</p><p>首先,我们必须把话说清楚:&quot;通往开悟的一步&quot;这种帖子里没有一丁点谦逊可言,哪怕你引用的是别人的话——那种居高临下的意思清清楚楚地写在脸上:&quot;啊,你们好,Facebook 上的朋友们。本人乃通晓人生奥秘之人——请允许我来教导你们,好让你们有朝一日也能开悟。&quot;</p><p>其次——你知道什么才能激励别人吗?是你<em>真正做成</em>了某件了不起的事,并把它作为榜样和激励留给他人。要让你的话本身具有激励作用,你得是一个有天赋的演讲者或作家,真的有原创的东西可说——我们都心知肚明,这不是你。所以你仅仅通过转发一些老掉牙的鸡汤名言就自认为是个激励人心的人物,这,嗯,是赤裸裸的自恋。你在假设,你,单凭作为你自己,就是一种激励。</p><p>第三,让我们来看看你发这些状态的真实动机——形象打造。你希望别人看到你有多么开悟,并钦佩你正在经历的这段灵性旅程。</p><p>* * *</p><p>我们那位朋友 Daniel 的帖子堪称壮举——短短一段话,他就直击我的灵魂,几乎集齐了上文讨论过的每一种糟糕状态类型和动机。可事情是这样的:如果你看他帖子下面,只能看到一堆点赞和几条友好评论。</p><p>这就是为什么令人不堪忍受的 Facebook 行为永远不会消失——Facebook 上没有&quot;踩&quot;按钮,没有&quot;翻白眼&quot;按钮,也没有&quot;中指&quot;按钮,而在别人状态下面的评论里当个混蛋又很不得体。所以烦人的状态只会被正向强化,而人们对自己经常拉低他人生活质量这一事实毫无自觉。</p><p>这里更重要的一点是:烦人状态的那些特质其实都是正常的人类特质——每个人都需要时不时向某人吹嘘一下,每个人都有软弱、需要关注、感到孤独的时刻,每个人身上都有些相当丑陋的一面,总会在某个时刻冒出来。</p><p><em>而这正是为什么你身边有爱你的人。</em></p><p>Daniel 和大多数人没有真正消化的一件事是:如果他们有 800 个 Facebook 好友,其中真正爱他们的只有大约 10 到 15 个。对于一个特别招人喜爱的人,也许能高达 30 个。*大概在 1% 到 4% 之间。*这意味着<strong>你的 Facebook 好友中,有 96% 到 99% 的人并不爱你。</strong></p><p>不爱你的人并不那么在乎你,不那么在乎你的日常或你的生活,他们大概率也没在特别为你加油,而且他们绝对不想跟你最糟糕的那些特质有任何关系。你为了满足自己情绪或自我需要而做的那些事,真的不该出现在他们的电脑屏幕上——就是不该。</p><p>好了,得走了。去健身房,然后吃晚饭,然后回家,然后睡觉。</p><p><strong>如果你喜欢这篇,可以看看:</strong></p><p><a href="https://waitbutwhy.com/2013/09/why-generation-y-yuppies-are-unhappy.html" target="_blank" rel="noreferrer">为什么 Y 世代的雅皮士不快乐</a></p><p><a href="https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html" target="_blank" rel="noreferrer">社交互动的巨大危险</a></p><p><a href="https://waitbutwhy.com/2014/05/secretly-hate-bars.html" target="_blank" rel="noreferrer">为什么你其实讨厌潮酷酒吧</a></p><h2 id="关于邮件的-11-件尴尬事" tabindex="-1"><a href="https://waitbutwhy.com/2013/12/11-awkward-things-about-email.html" target="_blank" rel="noreferrer">关于邮件的 11 件尴尬事</a> <a class="header-anchor" href="#关于邮件的-11-件尴尬事" aria-label="Permalink to &quot;[关于邮件的 11 件尴尬事](https://waitbutwhy.com/2013/12/11-awkward-things-about-email.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html&amp;description=7%20Ways%20to%20Be%20Insufferable%20on%20Facebook" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p>',127)])])}const P=o(d,[["render",A]]);export{I as __pageData,P as default};
